#!/usr/bin/env bash
# sop-kolb-pbl-5e-lb-t-092.sh — 课程设计 SOP（Kolb 体验学习圈 + PBL/5E + LB/T 092 官方七步） SOP walkthrough for 研学营地教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="研学营地教育"
WORKFLOW="课程设计 SOP（Kolb 体验学习圈 + PBL/5E + LB/T 092 官方七步）"

usage() {
  cat <<EOF
sop-kolb-pbl-5e-lb-t-092.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./sop-kolb-pbl-5e-lb-t-092.sh             # interactive
  ./sop-kolb-pbl-5e-lb-t-092.sh --dry-run
  ./sop-kolb-pbl-5e-lb-t-092.sh --json
  ./sop-kolb-pbl-5e-lb-t-092.sh --explain
  ./sop-kolb-pbl-5e-lb-t-092.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "课程设计 SOP（Kolb 体验学习圈 + PBL/5E + LB/T 092 官方七步）" 工作流。

一句话: 从「有了主题，但还是一堆景点和活动」走到「一份有学习目标、有体验、有反思、有评价、能落成研学手册的课程包」——这是**区分研学与旅游的命门工序**，也是 LB/T 092-2025 唯一给出官方流程的环节。

入门 SOP 共 7 步, 失败模式自检 3 项。

相关心智模型:
  • 「研学是课程不是行程」——教育属性优先: 研学/营地的本体是**课程**（有学习目标—实施—评价闭环），不是**行程**（景点+讲解词）；从业者用「教育本质」作为对抗旅游化、获客化、速成化的立场锚与对客叙事。
  • 体验—反思闭环（Kolb 圈）——「经验无反思即旅游」: 学习不是「去过/动手过」就发生，而要走完「具体经验→反思观察→抽象概念化→主动实践」的圈；**「反思/复盘」环节的有无，是研学区别于旅游的命门工序**。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**调研设计**：收集分析目标参与者需求，综合评估研学资源。跳过后果：课程与学段能力错配（小学生做研究生任务，或反之），现场带不动。 evidence: [W-S004]"
  "**主题设计**：结合课程目标与参与者特点定主题。跳过后果：活动无主线，沦为散点游玩。 evidence: [W-S004]"
  "**目标设计**：着眼「综合运用知识与技能解决问题」，用可测目标（布鲁姆动词把「参观X」改写为「能分析/能创造Y」）。跳过后果：无目标即无法评价，验收无依据=旅游不是研学。 evidence: [W-S004]（UbD/布鲁姆见 Track 02）"
  "**内容设计**：内容准确、系统、连贯、有逻辑。跳过后果：知识点零碎拼贴，学习不成体系。 evidence: [W-S004]"
  "**实施设计**：设计「导入→体验→评估」流程，注重探究性与互动性、亲身体验、分层设计。跳过后果：只有热闹的体验、没有建构与迁移（5E 的 Explain/Elaborate 缺位）。 evidence: [W-S004]"
  "**资料生成**：制定指导手册与任务/研学手册。跳过后果：导师无脚本、学生无任务载体，课程无法落地复制。 evidence: [W-S004]"
  "**评价优化**：组织多方评价、优化课程。跳过后果：课程不迭代，问题反复出现。 evidence: [W-S004]"
)
declare -a FAILURE_MODES=(
  "**景点堆砌、目标后补**：先排好去哪几个馆，再硬给每站编个「学习目标」，目标与活动两张皮。→ 逆向设计：先定可测目标与评价证据，再选能达成它的资源。 evidence: [W-S016]"
  "**有体验没反思（Kolb 断环）**：活动很热闹但没有反思观察与抽象概念化环节，学生「玩过就忘」。→ 每个体验后固定嵌入复盘/讨论/记录，闭合 Kolb 圈。 evidence: [W-S020]"
  "**手册=纪念册不是评价载体**：研学手册做成盖章打卡本，无任务、无记录、无评价表。→ 按 LB/T 092 附录 B（行前准备+学习材料+研学任务+评价表）做手册。 evidence: [W-S004]"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "sop-kolb-pbl-5e-lb-t-092-walkthrough"
fi
